// src/services/userService.js

import { db } from "./firebase";

import {
  collection,
  doc,
  getDocs,
  addDoc,
  updateDoc,
  deleteDoc
} from "firebase/firestore";


// fetch skills
export async function getSkills(userId){

  const ref =
  collection(
    db,
    "users",
    userId,
    "skills"
  );

  const snapshot =
  await getDocs(ref);

  return snapshot.docs.map(doc=>({

    id:doc.id,
    ...doc.data()

  }));

}


// add skill
export async function addSkill(userId,skill){

  const ref =
  collection(
    db,
    "users",
    userId,
    "skills"
  );

  const docRef =
  await addDoc(ref,skill);

  return docRef.id;

}


// update skill
export async function updateSkill(userId,id,data){

  const ref =
  doc(
    db,
    "users",
    userId,
    "skills",
    id
  );

  await updateDoc(ref,data);

}


// delete skill
export async function deleteSkill(userId,id){

  const ref =
  doc(
    db,
    "users",
    userId,
    "skills",
    id
  );

  await deleteDoc(ref);

}
